request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?org WHERE {
  ?model a bboExt:Model .
  ?model tai:normalizedId "1cd93309017949fdbebf0f7d7ea50b4a" .
  OPTIONAL { ?model bbo:name ?modelName . }
  ?model tai:belongsTo ?org .
  OPTIONAL { ?org rdfs:label ?orgName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?origId ?normId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  FILTER(CONTAINS(LCASE(STR(?origId)), "1cd93309017949fdbebf0f7d7ea50b4a") || 
         CONTAINS(LCASE(STR(?normId)), "1cd93309017949fdbebf0f7d7ea50b4a") ||
         CONTAINS(LCASE(STR(?model)), "1cd93309017949fdbebf0f7d7ea50b4a"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?msgFlow ?srcRef ?tgtRef ?msgRef WHERE {
  ?choreo a bboExt:Choreography .
  ?choreo bbo:id "sid_b7b36685_2b15_4bc0_8853_27012da21b61" .
  ?msgFlow a bboExt:MessageFlow .
  ?msgFlow tai:belongsTo ?choreo .
  OPTIONAL { ?msgFlow bboExt:sourceRef ?srcRef . }
  OPTIONAL { ?msgFlow bboExt:targetRef ?tgtRef . }
  OPTIONAL { ?msgFlow bboExt:messageRef ?msgRef . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
